import React, { useRef, useEffect, useState } from "react";
import styled from "styled-components";

// Configuration
const CONFIG = {
  columns: 2,
  itemsPerColumn: 3,
  scrollSpeed: 0.3,
  itemHeight: 50,
  gap: 5,
  colors: ["#f5f5f5", "#e0e0e0"],
  images: [
    "https://via.placeholder.com/50",
    "https://via.placeholder.com/50/cccccc",
  ],
};

// Styled components
const Container = styled.div`
  width: 100%;
  max-width: 320px;
  height: 70px;
  position: relative;
  overflow: hidden;
`;

const Rails = styled.div`
  display: flex;
  height: 100%;
`;

const Column = styled.div`
  width: 50%;
  position: relative;
`;

const Rail = styled.div<{ offset: number }>`
  position: absolute;
  width: 100%;
  transform: translateY(${(props) => props.offset}px);
`;

const Card = styled.div`
  width: 100%;
  height: ${CONFIG.itemHeight}px;
  margin-bottom: ${CONFIG.gap}px;
  background: ${(props) => CONFIG.colors[props.index % 2]};
  border-radius: 4px;
  border: 1px solid #84cc16;
`;

const DataList: React.FC = () => {
  const [offsets, setOffsets] = useState([0, 0]);
  const requestRef = useRef<number>();

  const columnHeight = (CONFIG.itemHeight + CONFIG.gap) * CONFIG.itemsPerColumn;

  const animate = (time: number) => {
    setOffsets((prev) =>
      prev.map((offset, i) => {
        const speed = i === 0 ? 0.3 : 0.5;
        let newOffset = offset - speed;
        return newOffset <= -columnHeight
          ? newOffset + columnHeight
          : newOffset;
      })
    );
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestRef.current!);
  }, []);

  return (
    <Container>
      <Rails>
        {[0, 1].map((i) => (
          <Column key={i}>
            <Rail offset={offsets[i]}>
              {[...Array(6)].map((_, j) => (
                <Card key={j} index={j}>
                  <img
                    src={CONFIG.images[j % 2]}
                    alt=""
                    width="50"
                    height="50"
                  />
                </Card>
              ))}
            </Rail>
          </Column>
        ))}
      </Rails>
    </Container>
  );
};

export default DataList;
